'use client'

import { useState, useEffect } from 'react'
import { supabase } from '../../../lib/supabase'
import { Header } from '../../../components/layout/Header'
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, 
  PieChart, Pie, Cell, LineChart, Line, ResponsiveContainer 
} from 'recharts'
import { FiUsers, FiMap, FiNavigation, FiBell, FiTrendingUp } from 'react-icons/fi'

const COLORS = ['#6b21a8', '#8b5cf6', '#10B981', '#EF4444', '#F59E0B']

export default function AnalyticsPage() {
  const [stats, setStats] = useState({
    totalUsers: 0,
    totalRoutes: 0,
    totalStops: 0,
    activeUsers: 0,
    notificationsSent: 0
  })
  
  const [userGrowth, setUserGrowth] = useState<any[]>([])
  const [routeData, setRouteData] = useState<any[]>([])
  const [notificationData, setNotificationData] = useState<any[]>([])
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    fetchAnalyticsData()
  }, [])

  const fetchAnalyticsData = async () => {
    try {
      // Fetch basic stats
      const [
        usersRes,
        routesRes,
        stopsRes,
        notificationsRes,
        userGrowthRes
      ] = await Promise.all([
        supabase.from('users').select('*', { count: 'exact' }),
        supabase.from('routes').select('*', { count: 'exact' }),
        supabase.from('stops').select('*', { count: 'exact' }),
        supabase.from('notifications').select('*'),
        supabase.from('users').select('created_at').order('created_at')
      ])

      // Process user growth data
      const growthData = processUserGrowth(userGrowthRes.data || [])
      const routeStats = await getRouteStats()
      const notificationStats = await getNotificationStats()

      setStats({
        totalUsers: usersRes.count || 0,
        totalRoutes: routesRes.count || 0,
        totalStops: stopsRes.count || 0,
        activeUsers: 0, // You'd need to calculate this based on last_seen
        notificationsSent: notificationsRes.data?.reduce((sum, n) => sum + n.sent_count, 0) || 0
      })

      setUserGrowth(growthData)
      setRouteData(routeStats)
      setNotificationData(notificationStats)
    } catch (error) {
      console.error('Failed to fetch analytics:', error)
    } finally {
      setLoading(false)
    }
  }

  const processUserGrowth = (users: any[]) => {
    const now = new Date()
    const last6Months = Array.from({ length: 6 }, (_, i) => {
      const date = new Date(now.getFullYear(), now.getMonth() - i, 1)
      return {
        month: date.toLocaleDateString('en-US', { month: 'short' }),
        users: 0
      }
    }).reverse()

    users.forEach(user => {
      const date = new Date(user.created_at)
      const monthIndex = last6Months.findIndex(m => 
        m.month === date.toLocaleDateString('en-US', { month: 'short' })
      )
      if (monthIndex !== -1) {
        last6Months[monthIndex].users++
      }
    })

    return last6Months
  }

  const getRouteStats = async () => {
    const { data } = await supabase
      .from('routes')
      .select('vehicle_type, approved')
    
    const stats = data?.reduce((acc: any, route) => {
      if (!acc[route.vehicle_type]) {
        acc[route.vehicle_type] = { approved: 0, pending: 0 }
      }
      if (route.approved) {
        acc[route.vehicle_type].approved++
      } else {
        acc[route.vehicle_type].pending++
      }
      return acc
    }, {})

    return Object.entries(stats || {}).map(([type, data]: any) => ({
      type,
      approved: data.approved,
      pending: data.pending
    }))
  }

  const getNotificationStats = async () => {
    const { data } = await supabase
      .from('notifications')
      .select('type, target_type, sent_count, read_count')
    
    return data?.map(n => ({
      type: n.type,
      sent: n.sent_count,
      read: n.read_count,
      rate: n.sent_count > 0 ? (n.read_count / n.sent_count * 100) : 0
    })) || []
  }

  return (
    <div className="space-y-6">
      <Header 
        title="Analytics Dashboard" 
        subtitle="Comprehensive analytics and insights for Ghana Trotro Transit"
      />

      {/* Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-6">
        <div className="bg-white p-6 rounded-lg shadow">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-text-light">Total Users</p>
              <p className="text-3xl font-bold text-text">{stats.totalUsers}</p>
            </div>
            <div className="p-3 bg-primary/10 rounded-lg">
              <FiUsers className="text-primary" size={24} />
            </div>
          </div>
          <div className="mt-4">
            <div className="flex items-center text-green-600">
              <FiTrendingUp className="mr-1" />
              <span className="text-sm">+12% from last month</span>
            </div>
          </div>
        </div>

        <div className="bg-white p-6 rounded-lg shadow">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-text-light">Total Routes</p>
              <p className="text-3xl font-bold text-text">{stats.totalRoutes}</p>
            </div>
            <div className="p-3 bg-primary/10 rounded-lg">
              <FiMap className="text-primary" size={24} />
            </div>
          </div>
          <div className="mt-4">
            <div className="flex items-center text-green-600">
              <FiTrendingUp className="mr-1" />
              <span className="text-sm">+8 new this month</span>
            </div>
          </div>
        </div>

        <div className="bg-white p-6 rounded-lg shadow">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-text-light">Total Stops</p>
              <p className="text-3xl font-bold text-text">{stats.totalStops}</p>
            </div>
            <div className="p-3 bg-primary/10 rounded-lg">
              <FiNavigation className="text-primary" size={24} />
            </div>
          </div>
        </div>

        <div className="bg-white p-6 rounded-lg shadow">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-text-light">Active Users</p>
              <p className="text-3xl font-bold text-text">{stats.activeUsers}</p>
            </div>
            <div className="p-3 bg-green-100 rounded-lg">
              <FiUsers className="text-green-600" size={24} />
            </div>
          </div>
          <div className="mt-4">
            <p className="text-sm text-text-light">Today</p>
          </div>
        </div>

        <div className="bg-white p-6 rounded-lg shadow">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-text-light">Notifications Sent</p>
              <p className="text-3xl font-bold text-text">{stats.notificationsSent}</p>
            </div>
            <div className="p-3 bg-purple-100 rounded-lg">
              <FiBell className="text-purple-600" size={24} />
            </div>
          </div>
          <div className="mt-4">
            <div className="flex items-center text-green-600">
              <FiTrendingUp className="mr-1" />
              <span className="text-sm">82% read rate</span>
            </div>
          </div>
        </div>
      </div>

      {/* Charts */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white p-6 rounded-lg shadow">
          <h3 className="text-lg font-semibold text-text mb-4">User Growth</h3>
          <div className="h-80">
            <ResponsiveContainer width="100%" height="100%">
              <LineChart data={userGrowth}>
                <CartesianGrid strokeDasharray="3 3" />
                <XAxis dataKey="month" />
                <YAxis />
                <Tooltip />
                <Legend />
                <Line type="monotone" dataKey="users" stroke="#6b21a8" strokeWidth={2} />
              </LineChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-6 rounded-lg shadow">
          <h3 className="text-lg font-semibold text-text mb-4">Route Approval Status</h3>
          <div className="h-80">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={routeData}>
                <CartesianGrid strokeDasharray="3 3" />
                <XAxis dataKey="type" />
                <YAxis />
                <Tooltip />
                <Legend />
                <Bar dataKey="approved" fill="#10B981" name="Approved" />
                <Bar dataKey="pending" fill="#F59E0B" name="Pending" />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-6 rounded-lg shadow">
          <h3 className="text-lg font-semibold text-text mb-4">Notification Performance</h3>
          <div className="h-80">
            <ResponsiveContainer width="100%" height="100%">
<PieChart>
  <Pie
    data={notificationData}
    cx="50%"
    cy="50%"
    labelLine={false}
    label={(entry: any) => `${entry.type}: ${entry.rate.toFixed(1)}%`}
    outerRadius={80}
    fill="#8884d8"
    dataKey="rate"
  >
    {notificationData.map((entry, index) => (
      <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
    ))}
  </Pie>
  <Tooltip formatter={(value: number) => `${value.toFixed(1)}%`} />
  <Legend />
</PieChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-6 rounded-lg shadow">
          <h3 className="text-lg font-semibold text-text mb-4">Active Hours</h3>
          <div className="h-80">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={[
                { hour: '6AM', users: 120 },
                { hour: '9AM', users: 450 },
                { hour: '12PM', users: 380 },
                { hour: '3PM', users: 320 },
                { hour: '6PM', users: 510 },
                { hour: '9PM', users: 180 }
              ]}>
                <CartesianGrid strokeDasharray="3 3" />
                <XAxis dataKey="hour" />
                <YAxis />
                <Tooltip />
                <Bar dataKey="users" fill="#8b5cf6" />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>

      {/* Additional Metrics */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="bg-white p-6 rounded-lg shadow">
          <h3 className="text-lg font-semibold text-text mb-4">Top Regions</h3>
          <div className="space-y-3">
            {['Accra', 'Kumasi', 'Tamale', 'Takoradi', 'Cape Coast'].map((region, index) => (
              <div key={region} className="flex items-center justify-between">
                <span className="text-text">{region}</span>
                <div className="flex items-center">
                  <div className="w-32 bg-gray-200 rounded-full h-2 mr-3">
                    <div 
                      className="bg-primary h-2 rounded-full" 
                      style={{ width: `${80 - index * 15}%` }}
                    />
                  </div>
                  <span className="text-text-light">{80 - index * 15}%</span>
                </div>
              </div>
            ))}
          </div>
        </div>

        <div className="bg-white p-6 rounded-lg shadow">
          <h3 className="text-lg font-semibold text-text mb-4">Popular Routes</h3>
          <div className="space-y-3">
            {[
              { name: 'Accra - Kumasi', searches: 1245 },
              { name: 'Accra - Tamale', searches: 892 },
              { name: 'Kumasi - Takoradi', searches: 745 },
              { name: 'Accra - Cape Coast', searches: 621 },
              { name: 'Tamale - Bolgatanga', searches: 432 }
            ].map(route => (
              <div key={route.name} className="flex items-center justify-between p-3 hover:bg-gray-50 rounded">
                <span className="font-medium">{route.name}</span>
                <span className="text-primary font-medium">{route.searches.toLocaleString()}</span>
              </div>
            ))}
          </div>
        </div>

        <div className="bg-white p-6 rounded-lg shadow">
          <h3 className="text-lg font-semibold text-text mb-4">System Health</h3>
          <div className="space-y-4">
            <div>
              <div className="flex justify-between mb-1">
                <span className="text-text-light">API Response Time</span>
                <span className="text-success font-medium">98%</span>
              </div>
              <div className="w-full bg-gray-200 rounded-full h-2">
                <div className="bg-success h-2 rounded-full" style={{ width: '98%' }} />
              </div>
            </div>
            <div>
              <div className="flex justify-between mb-1">
                <span className="text-text-light">Database Uptime</span>
                <span className="text-success font-medium">99.9%</span>
              </div>
              <div className="w-full bg-gray-200 rounded-full h-2">
                <div className="bg-success h-2 rounded-full" style={{ width: '99.9%' }} />
              </div>
            </div>
            <div>
              <div className="flex justify-between mb-1">
                <span className="text-text-light">Notification Delivery</span>
                <span className="text-success font-medium">95%</span>
              </div>
              <div className="w-full bg-gray-200 rounded-full h-2">
                <div className="bg-success h-2 rounded-full" style={{ width: '95%' }} />
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  )
}